import React, { useState } from 'react';

function QuestionForm({ onSubmit }) {
  const [answers, setAnswers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleInputChange = (index, value) => {
    const newAnswers = [...answers];
    newAnswers[index] = value;
    setAnswers(newAnswers);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    const apiKey = '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'; // Reemplaza con tu clave API

    try {
      // Realizar la solicitud a la API de OpenAI
      const response = await fetch('https://api.openai.com/v1/completions', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${apiKey}`, // Incluye la clave API
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          model: "gpt-3.5-turbo",  // Puedes usar otro modelo si lo prefieres
          prompt: `Evaluar las siguientes respuestas: ${answers.join(", ")}`,
          max_tokens: 100,
        }),
      });

      const result = await response.json();
      const analysis = result.choices[0].text;  // El análisis que regresa la API
      onSubmit(analysis);  // Llama la función onSubmit con el resultado
    } catch (err) {
      console.error('Error al conectar con la API', err);
      setError('Hubo un problema al procesar las respuestas.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <div>
        <label>Pregunta 1:</label>
        <input type="text" onChange={(e) => handleInputChange(0, e.target.value)} />
      </div>
      <div>
        <label>Pregunta 2:</label>
        <input type="text" onChange={(e) => handleInputChange(1, e.target.value)} />
      </div>
      {/* Puedes agregar más preguntas aquí */}
      <button type="submit" disabled={loading}>
        {loading ? 'Evaluando...' : 'Enviar respuestas'}
      </button>
      {error && <p>{error}</p>}
    </form>
  );
}

export default QuestionForm;
